/* append every current MP not already hand-rated in data.js */
(function(){
  var have = {}; G.POLITICIANS.forEach(function(p){ have[p.name.toLowerCase()]=true; });
  var alias = { "edward davey":"ed davey","stephen flynn":"stephen flynn" };
  var keys = G.PORTFOLIOS.map(function(p){return p.key;});
  function hash(s,salt){ var x=salt||7; for(var i=0;i<s.length;i++){ x=(x*31 + s.charCodeAt(i))>>>0; } return x; }
  function rng(s,salt,lo,hi){ return lo + (hash(s,salt) % (hi-lo+1)); }
  G.CURRENT_MPS.forEach(function(m){
    var key = m.name.toLowerCase();
    if (have[key] || have[alias[key]]) return;          // keep curated stars
    have[key] = true;
    var f1 = keys[hash(m.name,3) % keys.length];
    var f2 = keys[hash(m.name,9) % keys.length];
    var fits = f1===f2 ? [f1] : [f1,f2];
    G.POLITICIANS.push({
      name: m.name, party: m.party, era: "e7", fits: fits,
      stats: { appeal: rng(m.name,11,38,57), experience: rng(m.name,17,40,60),
               oratory: rng(m.name,23,38,58), statecraft: rng(m.name,29,42,60),
               partyMgmt: rng(m.name,31,42,60) },
      note: "MP for " + m.cons + " (" + m.party + ").", scope: "uk", gss: m.gss
    });
  });
})();
